<!DOCTYPE html>
<html>
<head>
  <title>Falling Sand</title>
  <style>
    body {
      background-color: #1e1e1e;
      display: flex;
      justify-content: center;
      align-items: center;
      height: 100vh;
      margin: 0;
      font-family: sans-serif;
    }

    #container {
      width: 800px;
      height: 600px;
      position: relative;
    }

    #canvas {
      background-color: #282828;
      border: none;
      display: block;
    }

    .button {
      background-color: #3e3e3e;
      color: white;
      padding: 10px 20px;
      border: none;
      cursor: pointer;
      margin: 5px;
      border-radius: 5px;
    }

    .button:hover {
      background-color: #4e4e4e;
    }
  </style>
</head>
<body>
  <div id="container">
    <h1>Falling Sand</h1>
    <canvas id="canvas"></canvas>
    <div>
      <button class="button" id="mat-sand">Sand</button>
      <button class="button" id="mat-water">Water</button>
      <button class="button" id="mat-wall">Wall</button>
      <button class="button" id="mat-acid">Acid</button>
      <button class="button" id="mat-empty">Empty (Eraser)</button>
      <button class="button" id="clear">Clear</button>
    </div>
  </div>

  <script>
    const w = 80;
    const h = 60;
    const canvas = document.getElementById('canvas');
    canvas.width = 400;
    canvas.height = 300;
    const ctx = canvas.getContext('2d');

    let grid = [];
    for (let y = 0; y < h; y++) {
      grid[y] = [];
      for (let x = 0; x < w; x++) {
        grid[y][x] = 'empty';
      }
    }

    window.sim = {
      w,
      h,
      tick: function(n) {
        for (let i = 0; i < n; i++) {
          simulate();
        }
      },
      get: function(x, y) {
        if (y >= 0 && y < h && x >= 0 && x < w) {
          return grid[y][x];
        }
        return 'empty';
      },
      set: function(x, y, material) {
        if (y >= 0 && y < h && x >= 0 && x < w) {
          grid[y][x] = material;
        }
      },
      clear: function() {
        for (let y = 0; y < h; y++) {
          for (let x = 0; x < w; x++) {
            grid[y][x] = 'empty';
          }
        }
      }
    };

    function simulate() {
      // Bottom row and side edges act as solid boundaries.
      for (let x = 0; x < w; x++) {
        if (grid[h - 1][x] !== 'empty') return;
      }
      for (let y = 0; y < h; y++) {
        if (grid[y][0] !== 'empty') return;
      }
      for (let x = 0; x < w; x++) {
        if (grid[h - 1][x] !== 'empty') return;
      }
      for (let y = 0; y < h; y++) {
        if (grid[y][w-1] !== 'empty') return;
      }

      for (let y = h - 1; y >= 0; y--) {
        for (let x = 0; x < w; x++) {
          const current = grid[y][x];
          if (current === 'sand') {
            let nextX = x;
            let nextY = y - 1;

            // Check for blockage and slide diagonally
            if (nextY >= 0 && grid[nextY][nextX] === 'empty') {
              grid[y][x] = 'empty';
              grid[nextY][nextX] = 'sand';
            } else {
              let direction = Math.random() < 0.5 ? -1 : 1; // Randomize direction
              nextX += direction;

              if (nextX >= 0 && nextX < w && nextY >= 0 && grid[nextY][nextX] === 'empty') {
                grid[y][x] = 'empty';
                grid[nextY][nextX] = 'sand';
              }
            }
          } else if (current === 'water') {
            let nextX = x;
            let nextY = y - 1;

            // Spread horizontally
            while (nextX >= 0 && grid[nextY][nextX] === 'empty') {
              nextX++;
            }

            if (nextX >= 0 && nextX < w && nextY >= 0) {
              grid[y][x] = 'empty';
              grid[nextY][nextX] = 'water';
            }
          } else if (current === 'acid') {
            let nextX = x;
            let nextY = y - 1;

            // Move like water and dissolve below/beside
            while (nextX >= 0 && grid[nextY][nextX] !== 'empty') {
              nextX++;
            }

            if (nextX >= 0 && nextX < w && nextY >= 0) {
              const target = grid[nextY][nextX];
              if (target === 'sand' || target === 'wall') {
                grid[nextY][nextX] = 'empty';
              }
              grid[y][x] = 'empty';
            }
          }
        }
      }
    }

    document.getElementById('mat-sand').addEventListener('click', () => window.sim.set(0, 0, 'sand'));
    document.getElementById('mat-water').addEventListener('click', () => window.sim.set(0, 0, 'water'));
    document.getElementById('mat-wall').addEventListener('click', () => window.sim.set(0, 0, 'wall'));
    document.getElementById('mat-acid').addEventListener('click', () => window.sim.set(0, 0, 'acid'));
    document.getElementById('mat-empty').addEventListener('click', () => window.sim.set(0, 0, 'empty'));
    document.getElementById('clear').addEventListener('click', () => window.sim.clear());

    function draw() {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
          const material = grid[y][x];
          const colorMap = {
            'empty': '#282828',
            'sand': '#ff9966',
            'water': '#77bbee',
            'wall': '#aaaaaa',
            'acid': '#ffcc99'
          };
          ctx.fillStyle = colorMap[material];
          ctx.fillRect(x * 20, y * 20, 20, 20);
        }
      }
    }

    setInterval(draw, 50); // Adjust interval for speed
  </script>
</body>
</html>
